"use strict";parserFactory.register("leafstudio.site",()=>new LeafStudioParser);class LeafStudioParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector(".novel_index");return util.hyperlinksToChapterList(t).reverse()}findContent(e){return e.querySelector(".small")}extractTitleImpl(e){return e.querySelector(".title")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"#font-options-bar, .confuse, .post-rating-wrapper, #donation-msg, .novel_nav_item, .text-center, .navigation"),super.removeUnwantedElementsFromContentElement(e)}extractDescription(e){return e.querySelector(".desc_div").textContent.trim()}findChapterTitle(e){return e.querySelector(".title")}}